import React, {  useEffect, useState } from "react";
import {useLocation, useNavigate} from "react-router-dom";
import './Logout.css';
import './Welcome';
import axios from "axios";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { faCoffee } from "@fortawesome/free-solid-svg-icons"; 
function Logout () {
    const [responses, setResponse] = useState([]);
    const [deleteResponse, setDeleteResponse] = useState([]);
    useEffect((userName) => {
        axios.get(`http://localhost:8080/user/${userName}/items`).then(response => setResponse(response.data))
        .catch(error => {console.log("An error happened:" + error)})
    }, []);
    const navigate = useNavigate();
    const location = useLocation();
    useEffect((userName, id) => {
        axios.delete(`http://localhost:8080/users/${userName}/items/${id}`).then(response => console.log(response.data))
       .catch(error => {console.log("An error happened:" + error)})
   }, []);
    const deleteEvent = (userName, id) => 
    {
        console.log(deleteResponse)
        return (
        <div>
        <table>
            <td>
            {
             deleteResponse.filter(response => (<tr><button onClick={() => deleteEvent("Abdi", "0")}>X</button>{response.id !== id}</tr>))
            }
            </td>
        </table>
        </div>
        )
    }
    return (
        <div className="list-of-itmes">
        <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.3.0/css/all.min.css"/>
        <div className="nav-bar">
        <div className="header">
        <a href="#default" className="logo">Productiv</a>
        <div className="header-right">
       {/* Create loader! */}
        <a href="#home" onClick={() => navigate('Welcome')}>My Account</a>
        <a href="/" onClick={() => navigate('/')} >Logout</a>
        </div>
        </div>
            <h1>Welcome {location.state.userName}!</h1>
        </div>
            <table>
                <td>
                {
                 responses.map(response => (<tr><FontAwesomeIcon icon="faCoffee" onClick={() => deleteEvent({})}/>{response.id} - {response.userName} - {response.targetDate} - {response.done}</tr>))
                }
                </td>
            </table>
        </div>
    )
}

export default Logout;
